import ast
import operator

def evaluate_expression(expr):
    """Evaluate a mathematical expression and return the numeric result.
    Supports +, -, *, / and parentheses.
    """
    try:
        tree = ast.parse(expr.strip(), mode='eval')
    except SyntaxError:
        raise ValueError("Invalid expression syntax")

    return _safe_eval(tree.body)

# Allowed operators mapping from ast node type
_BINARY_OPS = {
    ast.Add: operator.add,
    ast.Sub: operator.sub,
    ast.Mult: operator.mul,
    ast.Div: operator.truediv,
}

_UNARY_OPS = {
    ast.UAdd: operator.pos,
    ast.USub: operator.neg,
}

def _safe_eval(node):
    """Recursively evaluate an AST node, supporting only arithmetic."""
    if isinstance(node, ast.Constant) and isinstance(node.value, (int, float)):
        return node.value
    elif isinstance(node, ast.UnaryOp) and type(node.op) in _UNARY_OPS:
        operand = _safe_eval(node.operand)
        return _UNARY_OPS[type(node.op)](operand)
    elif isinstance(node, ast.BinOp) and type(node.op) in _BINARY_OPS:
        left = _safe_eval(node.left)
        right = _safe_eval(node.right)
        return _BINARY_OPS[type(node.op)](left, right)
    else:
        # Disallow any other node types (calls, attributes, names, etc.)
        raise ValueError("Expression contains unsupported operations")
