def merge_configs(base, override, merge_strategy="deep"):
    """Merge override into base config.

    If merge_strategy is 'shallow', performs a shallow merge.
    If merge_strategy is 'deep', recursively merges nested dicts.
    """
    if merge_strategy == "shallow":
        return {**base, **override}

    # deep merge: recursively merge nested dictionaries, without mutating base
    result = {}
    # Copy all keys from base
    for key in base:
        result[key] = base[key]
    # Apply overrides recursively
    for key in override:
        if (key in base and isinstance(base[key], dict) and isinstance(override[key], dict)):
            # Both are dicts: merge recursively
            result[key] = merge_configs(base[key], override[key], merge_strategy="deep")
        else:
            # Otherwise, override value takes precedence
            result[key] = override[key]
    return result
