def parse_entry(line):
    if not isinstance(line, str):
        return None

    # Must contain exactly one colon, not at start or end
    if line.count(':') != 1:
        return None

    key, value = line.split(':', 1)
    key = key.strip()
    value = value.strip()

    # Key must be non-empty after stripping
    if not key:
        return None

    # Try to convert value to number
    try:
        # Check if it's an integer (no decimal point)
        if '.' not in value:
            value = int(value)
        else:
            value = float(value)
    except ValueError:
        # Keep as string
        pass

    return (key, value)
